onStateCss:
/* il gioco inietta questa CSS quando integra l'asset; ciclo di fuoco 1.5s, tutto sincronizzato */
.on #charge-core{transform-origin:120px 150px;animation:pt-charge 1.5s ease-in-out infinite}
.on #status-light{animation:pt-status 0.5s steps(2) infinite}
.on #muzzle-glow{transform-origin:120px 330px;animation:pt-mglow 1.5s ease-in-out infinite}
.on #muzzle-flash{transform-origin:120px 332px;animation:pt-flash 1.5s ease-out infinite}
.on #plasma-bolt{transform-origin:120px 332px;animation:pt-fire 1.5s cubic-bezier(.4,0,.2,1) infinite}
.on #recoil{animation:pt-recoil 1.5s cubic-bezier(.3,0,.2,1) infinite}
.on .coil-orb{animation:pt-coil 1.5s linear infinite}
.on .coil-orb:nth-of-type(2){animation-delay:.16s}
.on .coil-orb:nth-of-type(3){animation-delay:.32s}
.on .coil-orb:nth-of-type(4){animation-delay:.48s}
@keyframes pt-charge{0%{transform:scale(.7);opacity:.5}55%{transform:scale(1.25);opacity:1}62%{transform:scale(.55);opacity:.95}100%{transform:scale(.7);opacity:.5}}
@keyframes pt-status{0%{opacity:1}100%{opacity:.3}}
@keyframes pt-mglow{0%,45%{opacity:.2}58%{opacity:1}80%{opacity:.25}100%{opacity:.2}}
@keyframes pt-flash{0%,52%{opacity:0;transform:scale(.4)}60%{opacity:1;transform:scale(1.15)}74%{opacity:0;transform:scale(1.4)}100%{opacity:0;transform:scale(.4)}}
@keyframes pt-fire{0%,55%{opacity:0;transform:translateY(0) scaleY(.6)}60%{opacity:1;transform:translateY(6px) scaleY(1)}92%{opacity:.9;transform:translateY(64px) scaleY(1.25)}100%{opacity:0;transform:translateY(72px) scaleY(1.3)}}
@keyframes pt-recoil{0%,54%{transform:translateY(0)}62%{transform:translateY(7px)}100%{transform:translateY(0)}}
@keyframes pt-coil{0%{opacity:.2}50%{opacity:1}100%{opacity:.2}}
